private String parseQuery(String solrQuery) {

	//１文字ずつ解析（特定文字で改行）
	List<String> lst = new ArrayList<String>();
	char[] chars = solrQuery.toCharArray();
	for (char c: chars) {
		int lstSize = lst.size();
		if (c=='(' || c==')') {
			String before = (lstSize > 0) ? lst.get(lstSize-1) : null;
			if (null != before && before.length()==0) {
				lst.set(lstSize-1, c + "");
			} else {
				lst.add(c+"");
			}
			lst.add("");
		} else if (c=='+') { //不要かも・・・
			String before = (lstSize > 0) ? lst.get(lstSize-1) : null;
			if (null != before && before.length()==0) {
			} else {
				lst.add(" ");
			}
		} else if (c=='&') {
			if (lstSize > 0) {
				if (lst.get(lstSize-1).endsWith(")")) {
					lst.add(c + "");
				} else {
					lst.set(lstSize-1, lst.get(lstSize-1) + "\n" + c);
				}
			} else {
				lst.add(c + "");
			}
		} else {
			if (lstSize > 0) {
				lst.set(lstSize-1, lst.get(lstSize-1) + c);
			} else {
				lst.add(c + "");
			}
		}
	}

	//インデント調整１
	StringBuilder sb = new StringBuilder();
	int idx = 0;
	for (String s : lst) {
		s = s.trim();
		if ("(".equals(s)) {
			idx++;
			sb.append("(\n").append(StringUtils.repeat("\t", idx));
		} else if (")".equals(s)) {
			idx--;
			sb.append("\n").append(StringUtils.repeat("\t", idx)).append(")");
		} else if ("AND".equalsIgnoreCase(s)) {
			sb.append(" And ");
		} else if ("OR".equalsIgnoreCase(s)) {
			sb.append(" Or ").append("\n").append(StringUtils.repeat("\t", idx));
		} else {
			String tab = StringUtils.repeat("\t", idx);
			if (s.startsWith("&")) s = "\n" + s;
			s = s.replaceAll(" AND ", " And \n" + tab)
					.replaceAll("^AND ", " And \n" + tab)
					.replaceAll(" AND$", " And ")
					.replaceAll(" OR ", " Or \n" + tab)
					.replaceAll("^OR ", " Or \n" + tab)
					.replaceAll(" OR$", " Or ");
			sb.append(s);
		}
	}

	//インデント調整２
	String[] lines = sb.toString().split("\n");
	sb = new StringBuilder();
	for (String line : lines) {
		if (line.startsWith("&sort=")) {
			line = line.replaceAll("&sort=", "&sort=\n\t").replaceAll(" asc,", " asc,\n\t").replaceAll(" desc,", " desc,\n\t");
		} else if (line.startsWith("&facet.field=")) {
			line = line.replaceAll("&facet.field=", "&facet.field=\n\t").replaceAll(",", ",\n\t");
		} else if (line.startsWith("&group.field=")) {
			line = line.replaceAll("&group.field=", "&group.field=\n\t").replaceAll(",", ",\n\t");
		} else if (line.startsWith("&fl=")) {
			line = line.replaceAll("&fl=", "&fl=\n\t").replaceAll(",", ",\n\t");
		}
		sb.append(line).append("\n");
	}

	// 仕上げの微調整
	return sb.toString()
			//.replaceAll("(\t+)(\\d+ Or)( \n)","$2 ") // 駅コードなどの Or 連結の改行除去 -- いまいち
			.replaceAll(" Or \n\t+\\("," Or (\n") // Or後のカッコを微調整
			.replaceAll("\n\n+","\n"); //不要改行削除
}

